using Mayordomo.Transversal.Common.Enums;
using Mayordomo.Transversal.Common.Interfaces;
using Microsoft.AspNetCore.Hosting;

namespace Mayordomo.Transversal.Common.Helpers
{
    public class PathConstans : IPathConstans
    {
        private const string Music = $"Images\\User\\Account";
        private const string Image = $"Images\\Company";

        private const string ImageNotFound = "";
        private readonly IHostingEnvironment _env;

        public PathConstans(IHostingEnvironment env)
        {
            _env = env;
        }

        public string GetFullPath(TypePath typeImage)
        {
            var root = _env.WebRootPath ?? Path.Combine(Directory.GetCurrentDirectory(), "wwwroot");

            var relativePath = typeImage switch
            {
                TypePath.Music => Music,
                TypePath.Image => Image,
                _ => ImageNotFound
            };
            return Path.Combine(root, relativePath);
        }
    }
}
